  ('bookkeeper-moex-01383', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '關於102年度起我國個人基本所得額之計算，下列敘述何者正確？', '["應加計非上市櫃證券交易所得、私募證券投資信託基金之受益憑證之交易所得", "應加計所得基本稅額條例施行後所訂立之所有人壽保險及年金保險，受益人受領之保險給付", "受益人受領之人壽保險及年金保險給付，每一申報戶全年合計數在新臺幣三千萬元以下部分，免予計入", "應加計於申報綜合所得稅時減除之非現金捐贈金額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01384', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營利事業於一百零二年度以後出售其持有滿幾年以上屬所得稅法第四條之一規定之股票者，於計算其當年度 證券交易所得時，減除其當年度出售持有滿相同年度以上股票之交易損失，餘額為正者，以餘額半數計入 當年度證券交易所得？', '["一年", "三年", "五年", "七年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01385', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得基本稅額條例規定，基本所得額每遇消費者物價指數較上次調整年度之指數上漲累計達百分之多少以 上時，按上漲程度調整之？', '["百分之三", "百分之五", "百分之十", "無指數調整規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01386', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '在臺以新臺幣支付國外佣金者，原則上應在不超過出口貨物價款多少範圍內取具國外代理商或代銷商名義出 具之收據為憑予以認定？', '["百分之一", "百分之二", "百分之三", "百分之四"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01387', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營利事業依營利事業所得稅查核準則規定列支之製造費用及營業費用，如係取得小規模營利事業出具之普通 收據，其全年累計金額以不超過當年度經稽徵機關核定之製造費用及營業費用之總額多少為限，超過部分， 不予認定？', '["百分之三十", "百分之二十", "千分之二十", "千分之三十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01388', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則規定，修繕費支出其效能非幾年內所能耗竭者，應作為資本支出？', '["一年", "二年", "三年", "五年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01389', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營利事業之捐贈，依政治獻金法規定，對政黨、政治團體及擬參選人之捐贈，以不超過所得額百分之十為限， 其總額並不得超過新臺幣多少萬元？', '["十萬元", "二十萬元", "三十萬元", "五十萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01390', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則規定，資產之交換，應如何入帳？', '["如時價能可靠衡量，應以時價入帳，但不認列交換損益", "如時價能可靠衡量，應以時價入帳，如有交換利益，應予認列", "一律以換出資產之帳面價值入帳", "一律以換入資產之帳面價值入帳，並認列交換損益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01391', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營利事業對合於運動產業發展條例第二十六條、中小企業發展基金之捐贈，應如何列為當年度捐贈費用？', '["不受金額限制，全數可列為捐贈費用", "以不超過當年度所得額百分之十為限，其總額並不得超過新臺幣五十萬元", "以不超過當年度所得額百分之二十為限，其總額並不得超過新臺幣一千萬元", "不得列為費用或損失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
